<span class="line">    <span class="token keyword">Dim</span> SelectText <span class="token keyword">As</span> <span class="token keyword">String</span></span>
<span class="line">    <span class="token keyword">Dim</span> PinYinText <span class="token keyword">As</span> <span class="token keyword">String</span></span>
<span class="line">    Selection<span class="token punctuation">.</span>WholeStory</span>
<span class="line">    TextLength <span class="token operator">=</span> Selection<span class="token punctuation">.</span>Characters<span class="token punctuation">.</span>Count</span>
<span class="line">    Selection<span class="token punctuation">.</span><span class="token keyword">GoTo</span> What<span class="token punctuation">:</span><span class="token operator">=</span>wdGoToHeading<span class="token punctuation">,</span> Which<span class="token punctuation">:</span><span class="token operator">=</span>wdGoToAbsolute<span class="token punctuation">,</span> Count<span class="token punctuation">:</span><span class="token operator">=</span><span class="token number">1</span></span>
<span class="line">    <span class="token keyword">For</span> i <span class="token operator">=</span> <span class="token number">0</span> <span class="token keyword">To</span> TextLength</span>
<span class="line">        Selection<span class="token punctuation">.</span>MoveRight Unit<span class="token punctuation">:</span><span class="token operator">=</span>wdCharacter<span class="token punctuation">,</span> Count<span class="token punctuation">:</span><span class="token operator">=</span><span class="token number">1</span></span>
<span class="line">        Selection<span class="token punctuation">.</span>MoveLeft Unit<span class="token punctuation">:</span><span class="token operator">=</span>wdCharacter<span class="token punctuation">,</span> Count<span class="token punctuation">:</span><span class="token operator">=</span><span class="token number">1</span><span class="token punctuation">,</span> Extend<span class="token punctuation">:</span><span class="token operator">=</span>wdExtend</span>
<span class="line">        <span class="token keyword">With</span> Selection</span>
<span class="line">            SelectText <span class="token operator">=</span> <span class="token punctuation">.</span>Text <span class="token comment">'基准文字</span></span>
<span class="line">            <span class="token keyword">If</span> isChinese<span class="token punctuation">(</span>AscW<span class="token punctuation">(</span>SelectText<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token keyword">Then</span> <span class="token comment">'判断是否为中文字符</span></span>
<span class="line">                PinYinText <span class="token operator">=</span> GetPhonetic<span class="token punctuation">(</span>SelectText<span class="token punctuation">)</span> <span class="token comment">'基准文字 转换为 拼音文字</span></span>
<span class="line">                <span class="token keyword">If</span> PinYinText <span class="token operator">&lt;</span><span class="token operator">></span> <span class="token string">""</span> <span class="token keyword">Then</span></span>
<span class="line">                    <span class="token punctuation">.</span>Range<span class="token punctuation">.</span>PhoneticGuide Text<span class="token punctuation">:</span><span class="token operator">=</span>PinYinText<span class="token punctuation">,</span> Alignment<span class="token punctuation">:</span><span class="token operator">=</span>wdPhoneticGuideAlignmentCenter<span class="token punctuation">,</span> <span class="token operator">_</span></span>
<span class="line">                    Raise<span class="token punctuation">:</span><span class="token operator">=</span><span class="token number">0</span><span class="token punctuation">,</span> <span class="token operator">_</span></span>
